# Minimal function-calling dispatcher (OpenAI SDK)
import json
import openai

client = openai.OpenAI()

tools = [
    {
        "type": "function",
        "function": {
            "name": "get_weather",
            "description": "Return current weather for a city.",
            "parameters": {
                "type": "object",
                "properties": {
                    "city": {
                        "type": "string",
                        "description": "City name, e.g. 'Tokyo'"
                    },
                    "units": {
                        "type": "string",
                        "enum": ["celsius", "fahrenheit"],
                        "description": "Temperature units"
                    }
                },
                "required": ["city", "units"]
            }
        }
    }
]

def get_weather(city: str, units: str) -> dict:
    # Stub — replace with real API call
    return {"city": city, "temp": 22, "units": units, "condition": "sunny"}

def run(user_message: str) -> str:
    messages = [{"role": "user", "content": user_message}]
    for _ in range(10):  # step limit
        response = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=messages,
            tools=tools,
        )
        msg = response.choices[0].message
        messages.append(msg)  # append assistant turn
        if msg.tool_calls is None:
            return msg.content  # text response; we're done
        for tc in msg.tool_calls:
            args = json.loads(tc.function.arguments)
            # Dispatch
            if tc.function.name == "get_weather":
                result = get_weather(**args)
            else:
                result = {"error": f"Unknown tool: {tc.function.name}"}
            messages.append({
                "role": "tool",
                "tool_call_id": tc.id,
                "content": json.dumps(result),
            })
    return "Step limit reached."

print(run("What is the weather in Tokyo in celsius?"))

