import OpenAI from "openai";

const client = new OpenAI();

const tools = [
  {
    type: "function",
    function: {
      name: "search_products",
      description: "Search the product catalog by keyword.",
      parameters: {
        type: "object",
        properties: {
          query:    { type: "string",  description: "Search keyword" },
          max_results: { type: "integer", description: "Max items to return", default: 5 }
        },
        required: ["query"]
      }
    }
  },
  {
    type: "function",
    function: {
      name: "get_inventory",
      description: "Return stock count for a product ID.",
      parameters: {
        type: "object",
        properties: {
          product_id: { type: "string", description: "Product SKU" }
        },
        required: ["product_id"]
      }
    }
  }
];

// Stub implementations
function search_products({ query, max_results = 5 }) {
  return [{ id: "SKU-101", name: "Laptop Stand Pro", price: 49.99 }];
}
function get_inventory({ product_id }) {
  return { product_id, stock: 12 };
}

const dispatch = { search_products, get_inventory };

async function runAgent(userMessage) {
  const messages = [{ role: "user", content: userMessage }];

  for (let step = 0; step < 10; step++) {
    const response = await client.chat.completions.create({
      model: "gpt-4o-mini",
      messages,
      tools,
    });

    const msg = response.choices[0].message;
    messages.push(msg);

    if (!msg.tool_calls || msg.tool_calls.length === 0) {
      return msg.content; // final answer
    }

    // Execute ALL tool calls in parallel
    const results = await Promise.all(
      msg.tool_calls.map(async (tc) => {
        const args = JSON.parse(tc.function.arguments);
        const fn = dispatch[tc.function.name];
        const result = fn ? fn(args) : { error: "unknown tool" };
        return { role: "tool", tool_call_id: tc.id, content: JSON.stringify(result) };
      })
    );

    messages.push(...results);
  }
  return "Step limit reached.";
}

const answer = await runAgent(
  "Find laptop stands and tell me how many SKU-101 we have in stock."
);
