from typing import Literal
from pydantic import BaseModel, Field
import json, openai

client = openai.OpenAI()

# Define tool schemas using Pydantic for validation on the orchestrator side
class RefundArgs(BaseModel):
    order_id: str = Field(pattern=r'^ORD-\d{6}$')
    amount: float = Field(gt=0, le=500)
    reason: Literal["damaged", "not_received", "wrong_item", "other"]

TOOLS = [
    {
        "type": "function",
        "function": {
            "name": "issue_refund",
            "description": "Initiate a refund for a customer order.",
            "parameters": {
                "type": "object",
                "properties": {
                    "order_id": {"type": "string", "description": "Order ID, format ORD-XXXXXX"},
                    "amount":   {"type": "number", "description": "Refund amount in USD, max 500"},
                    "reason":   {"type": "string", "enum": ["damaged", "not_received", "wrong_item", "other"]}
                },
                "required": ["order_id", "amount", "reason"]
            }
        }
    }
]

def handle_tool_call(tc) -> str:
    if tc.function.name == "issue_refund":
        raw = json.loads(tc.function.arguments)
        try:
            args = RefundArgs(**raw)       # Pydantic validates types + constraints
        except Exception as e:
            return json.dumps({"error": str(e)})
        # Business-rule gate
        if args.amount > 500:
            return json.dumps({"status": "pending_approval", "message": "Requires manager sign-off."})
        # Execute real refund API here...
        return json.dumps({"status": "approved", "refund_id": "REF-999"})
    return json.dumps({"error": "unknown tool"})

messages = [
    {"role": "system", "content": "You are a customer support agent. Use tools to take actions."},
    {"role": "user",   "content": "Please refund order ORD-004821 for $39.99 — it arrived damaged."}
]
for _ in range(5):
    resp = client.chat.completions.create(model="gpt-4o-mini", messages=messages, tools=TOOLS)
    msg = resp.choices[0].message
    messages.append(msg)
    if not msg.tool_calls:
        print(msg.content)
        break
    for tc in msg.tool_calls:
        result = handle_tool_call(tc)
        messages.append({"role": "tool", "tool_call_id": tc.id, "content": result})
